              Sửa
            </button>

            {/* Toggle availability */}
            <button
              onClick={() => onToggleAvailable(item)}
              className={`
                min-h-[40px] inline-flex items-center gap-1.5 rounded-xl px-3.5 py-2 text-xs font-semibold ring-1 ring-inset
                transition-colors active:scale-[0.96]
                ${
                  item.available
                    ? 'bg-orange-50 text-orange-700 ring-orange-200 hover:bg-orange-100'
                    : 'bg-emerald-50 text-emerald-700 ring-emerald-200 hover:bg-emerald-100'
                }
              `}
              style={{ transitionProperty: 'background-color, transform' }}
            >
              {item.available ? (
                <>
                  <svg
                    xmlns="http://www.w3.org/2000/svg"
                    fill="none"
                    viewBox="0 0 24 24"
                    strokeWidth={2}
                    stroke="currentColor"
                    className="w-3.5 h-3.5"
                  >
                    <path
                      strokeLinecap="round"
                      strokeLinejoin="round"
                      d="M18.364 18.364A9 9 0 0 0 5.636 5.636m12.728 12.728A9 9 0 0 1 5.636 5.636m12.728 12.728L5.636 5.636"
                    />
                  </svg>
                  Hết hàng
                </>
              ) : (
                <>
                  <svg
                    xmlns="http://www.w3.org/2000/svg"
                    fill="none"
                    viewBox="0 0 24 24"
                    strokeWidth={2}
                    stroke="currentColor"
                    className="w-3.5 h-3.5"
                  >
                    <path strokeLinecap="round" strokeLinejoin="round" d="m4.5 12.75 6 6 9-13.5" />
                  </svg>
                  Còn hàng
                </>
              )}
            </button>

            {/* Delete (two-tap) */}
            <button
              onClick={handleDeleteTap}
              className={`
                min-h-[40px] inline-flex items-center gap-1.5 rounded-xl px-3.5 py-2 text-xs font-semibold
                transition-all duration-150 active:scale-[0.96]
                ${
                  confirmingDelete
                    ? 'bg-red-600 text-white shadow-md shadow-red-900/20 ring-0'
                    : 'bg-red-50 text-red-600 ring-1 ring-inset ring-red-200 hover:bg-red-100'
                }
              `}
              style={{ transitionProperty: 'background-color, color, transform, box-shadow' }}
            >
              <svg
                xmlns="http://www.w3.org/2000/svg"
                fill="none"
                viewBox="0 0 24 24"
                strokeWidth={2}
                stroke="currentColor"
                className="w-3.5 h-3.5"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  d="m14.74 9-.346 9m-4.788 0L9.26 9m9.968-3.21c.342.052.682.107 1.022.166m-1.022-.165L18.16 19.673a2.25 2.25 0 0 1-2.244 2.077H8.084a2.25 2.25 0 0 1-2.244-2.077L4.772 5.79m14.456 0a48.108 48.108 0 0 0-3.478-.397m-12 .562c.34-.059.68-.114 1.022-.165m0 0a48.11 48.11 0 0 1 3.478-.397m7.5 0v-.916c0-1.18-.91-2.164-2.09-2.201a51.964 51.964 0 0 0-3.32 0c-1.18.037-2.09 1.022-2.09 2.201v.916m7.5 0a48.667 48.667 0 0 0-7.5 0"
                />
              </svg>
              {confirmingDelete ? 'Xác nhận xoá?' : 'Ẩn'}
            </button>
          </>
        )}
      </div>
    </div>
  )
}

import { prisma } from '@/lib/prisma'
import ErrorPage from '@/components/order/ErrorPage'
import MenuView from '@/components/order/MenuView'
import CartUI from '@/components/order/CartUI'
import { CartProvider } from '@/components/order/CartProvider'

const INVALID_TABLE_MSG =
  'Bàn không hợp lệ. Vui lòng scan lại mã QR tại bàn của bạn.'

export default async function OrderPage({
  searchParams,
}: {
  searchParams: Promise<{ [key: string]: string | string[] | undefined }>
}) {
  const { table } = await searchParams

  // --- Table validation ---
  const tableStr = typeof table === 'string' ? table : undefined
  const tableNum = tableStr ? parseInt(tableStr, 10) : NaN

  if (!tableStr || isNaN(tableNum)) {
    return <ErrorPage message={INVALID_TABLE_MSG} />
  }

  const tableRecord = await prisma.table.findFirst({
    where: { number: tableNum },
  })

  if (!tableRecord) {
    return <ErrorPage message={INVALID_TABLE_MSG} />
  }

  // --- Fetch all menu items sorted by sortOrder ---
  const menuItems = await prisma.menuItem.findMany({
    where: { hidden: false },
    orderBy: { sortOrder: 'asc' },
  })

  // Serialize to plain objects for client component boundary
  const items = menuItems.map((item) => ({
    id: item.id,
    name: item.name,
    category: item.category as 'DRINK' | 'FOOD',
    price: item.price,
    description: item.description,
    available: item.available,
    sortOrder: item.sortOrder,
  }))

  const tableInfo = {
    id: tableRecord.id,
    number: tableRecord.number,
    name: tableRecord.name,
  }

  return (
    <div className="min-h-dvh bg-amber-50">
      <CartProvider tableId={tableInfo.id}>
        <CartUI tableId={tableInfo.id} tableNumber={tableInfo.number}>
          <MenuView menuItems={items} table={tableInfo} />
        </CartUI>
      </CartProvider>
    </div>
  )
}

